const FadeInSection: React.FC<{ children: React.ReactNode; delay?: number; direction?: 'up' | 'down' | 'none' }> = ({ children, delay = 0, direction = 'up' }) => {
  const [isVisible, setIsVisible] = useState(false);
  const domRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      });
    }, { threshold: 0.1 });

    const currentRef = domRef.current;
    if (currentRef) observer.observe(currentRef);
    return () => { if (currentRef) observer.unobserve(currentRef); };
  }, []);

  const getTransform = () => {
    if (direction === 'none') return '';
    return isVisible ? 'translateY(0)' : direction === 'up' ? 'translateY(60px)' : 'translateY(-60px)';
  };

  return (
    <div
      ref={domRef}
      className={`transition-all duration-[1400ms] cubic-bezier(0.16, 1, 0.3, 1) ${
        isVisible ? 'opacity-100 scale-100' : 'opacity-0 scale-[0.98]'
      }`}
      style={{ 
        transitionDelay: `${delay}ms`,
        transform: getTransform()
      }}
    >
      {children}
    </div>
  );
};

